#include <bits/stdc++.h>
using namespace std;
#define dbg(x) cerr<<#x" = "<<(x)<<endl;
#define ll long long
const int N=2005;
unordered_map<string,int> mp;
string s[N];
int n,ans;
int main()
{
	ios::sync_with_stdio(0);
	cin.tie(0),cout.tie(0);
//	freopen(".in","r",stdin);
//	freopen(".out","w",stdout);
	cin>>n;
	for(int i=1;i<=n;i++)
	{
		cin>>s[i];
		mp[s[i]]++;
	}
	for(int i=1;i<=n;i++)
	{
		int sum=0;
		string tmp="";
		for(int j=0;j<s[i].size();j++)
		{
			tmp+=s[i][j];
			sum+=mp[tmp];
		}
		ans=max(ans,sum);
	}
	cout<<ans;
	return 0;
}
